const { chromium } = require('playwright');

class PlaywrightBrowserless {
  constructor() {
    this.browserlessUrl = 'ws://82.29.181.193:3001';
    this.token = 'zjs-secure-playwright-token-0815';
  }

  async connect() {
    // Connect to browserless instance
    this.browser = await chromium.connectOverCDT({
      wsEndpoint: `${this.browserlessUrl}?token=${this.token}`
    });
    return this.browser;
  }

  async automateEcommerce(url) {
    const browser = await this.connect();
    const context = await browser.newContext({
      viewport: { width: 1920, height: 1080 },
      userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
    });

    const page = await context.newPage();

    try {
      console.log(`🚀 Starting automation for: ${url}`);

      // Navigate and wait for page load
      await page.goto(url, { waitUntil: 'networkidle' });

      // Extract product information
      const products = await page.evaluate(() => {
        const productElements = document.querySelectorAll('[data-testid="product"], .product-item, .product-card');
        return Array.from(productElements).map(product => ({
          title: product.querySelector('h1, h2, h3, .title, .product-title')?.textContent?.trim(),
          price: product.querySelector('.price, .cost, [data-testid="price"]')?.textContent?.trim(),
          image: product.querySelector('img')?.src,
          link: product.querySelector('a')?.href
        })).filter(p => p.title || p.price);
      });

      // Handle cookie consent
      await this.handleCookieConsent(page);

      // Search functionality
      const searchResults = await this.performSearch(page, 'laptop');

      // Form interactions
      const formData = await this.fillContactForm(page);

      // Take screenshots
      const fullPageScreenshot = await page.screenshot({ 
        fullPage: true,
        type: 'png'
      });

      // Generate PDF
      const pdf = await page.pdf({
        format: 'A4',
        printBackground: true,
        margin: { top: '1cm', bottom: '1cm', left: '1cm', right: '1cm' }
      });

      return {
        url,
        products,
        searchResults,
        formData,
        screenshots: {
          fullPage: fullPageScreenshot.toString('base64')
        },
        pdf: pdf.toString('base64'),
        timestamp: new Date().toISOString()
      };

    } finally {
      await context.close();
      await browser.close();
    }
  }

  async handleCookieConsent(page) {
    // Common cookie consent selectors
    const cookieSelectors = [
      'button[data-testid="accept-cookies"]',
      '.cookie-accept',
      '#accept-cookies',
      'button:has-text("Accept")',
      'button:has-text("Allow")',
      'button:has-text("OK")'
    ];

    for (const selector of cookieSelectors) {
      try {
        await page.click(selector, { timeout: 2000 });
        console.log(`✅ Accepted cookies using: ${selector}`);
        break;
      } catch (e) {
        // Try next selector
      }
    }
  }

  async performSearch(page, searchTerm) {
    try {
      // Find search input
      const searchInput = await page.locator('input[type="search"], input[placeholder*="search"], #search, .search-input').first();

      if (await searchInput.isVisible()) {
        await searchInput.fill(searchTerm);
        await searchInput.press('Enter');

        // Wait for results
        await page.waitForLoadState('networkidle');

        // Extract search results
        const results = await page.evaluate(() => {
          const resultElements = document.querySelectorAll('.search-result, .result-item, [data-testid="search-result"]');
          return Array.from(resultElements).slice(0, 10).map(result => ({
            title: result.querySelector('h1, h2, h3, .title')?.textContent?.trim(),
            description: result.querySelector('p, .description, .snippet')?.textContent?.trim(),
            link: result.querySelector('a')?.href
          }));
        });

        return { searchTerm, results, count: results.length };
      }
    } catch (error) {
      console.log(`⚠️ Search failed: ${error.message}`);
      return { searchTerm, results: [], error: error.message };
    }
  }

  async fillContactForm(page) {
    try {
      // Look for contact forms
      const forms = await page.locator('form').all();

      for (const form of forms) {
        const hasEmailInput = await form.locator('input[type="email"], input[name*="email"]').count() > 0;
        const hasNameInput = await form.locator('input[name*="name"], input[placeholder*="name"]').count() > 0;

        if (hasEmailInput && hasNameInput) {
          // Fill the form
          await form.locator('input[name*="name"], input[placeholder*="name"]').first().fill('John Doe');
          await form.locator('input[type="email"], input[name*="email"]').first().fill('john.doe@example.com');

          const messageField = form.locator('textarea, input[name*="message"]').first();
          if (await messageField.isVisible()) {
            await messageField.fill('This is an automated test message.');
          }

          console.log('✅ Contact form filled successfully');
          return { status: 'filled', form: 'contact' };
        }
      }

      return { status: 'no_form_found' };
    } catch (error) {
      return { status: 'error', error: error.message };
    }
  }

  async automateGoogleSearch(query) {
    const browser = await this.connect();
    const page = await browser.newPage();

    try {
      await page.goto('https://www.google.com');

      // Handle cookie consent
      try {
        await page.click('button:has-text("Accept all")', { timeout: 3000 });
      } catch (e) {
        // Cookie consent not found, continue
      }

      // Perform search
      await page.fill('input[name="q"]', query);
      await page.press('input[name="q"]', 'Enter');
      await page.waitForLoadState('networkidle');

      // Extract results
      const results = await page.evaluate(() => {
        const searchResults = document.querySelectorAll('[data-result-index]');
        return Array.from(searchResults).slice(0, 10).map(result => ({
          title: result.querySelector('h3')?.textContent,
          url: result.querySelector('a')?.href,
          snippet: result.querySelector('[data-sncf="1"]')?.textContent
        }));
      });

      return { query, results, count: results.length };

    } finally {
      await page.close();
      await browser.close();
    }
  }

  async monitorPrices(products) {
    const browser = await this.connect();
    const results = [];

    for (const product of products) {
      const page = await browser.newPage();

      try {
        await page.goto(product.url);

        // Extract current price
        const currentPrice = await page.evaluate((selectors) => {
          for (const selector of selectors) {
            const element = document.querySelector(selector);
            if (element) {
              return element.textContent.trim();
            }
          }
          return null;
        }, [
          '.price', '.cost', '[data-testid="price"]', 
          '.price-current', '.current-price', '.sale-price'
        ]);

        results.push({
          name: product.name,
          url: product.url,
          currentPrice,
          previousPrice: product.lastKnownPrice,
          priceChanged: currentPrice !== product.lastKnownPrice,
          timestamp: new Date().toISOString()
        });

      } catch (error) {
        results.push({
          name: product.name,
          url: product.url,
          error: error.message,
          timestamp: new Date().toISOString()
        });
      } finally {
        await page.close();
      }
    }

    await browser.close();
    return results;
  }

  async generateReports(urls) {
    const browser = await this.connect();
    const reports = [];

    for (const url of urls) {
      const page = await browser.newPage();

      try {
        await page.goto(url, { waitUntil: 'networkidle' });

        // Performance metrics
        const metrics = await page.evaluate(() => ({
          loadTime: performance.timing.loadEventEnd - performance.timing.navigationStart,
          domReady: performance.timing.domContentLoadedEventEnd - performance.timing.navigationStart,
          resourceCount: performance.getEntriesByType('resource').length
        }));

        // SEO analysis
        const seoData = await page.evaluate(() => ({
          title: document.title,
          metaDescription: document.querySelector('meta[name="description"]')?.content,
          headings: {
            h1: Array.from(document.querySelectorAll('h1')).map(h => h.textContent),
            h2: Array.from(document.querySelectorAll('h2')).map(h => h.textContent),
            h3: Array.from(document.querySelectorAll('h3')).map(h => h.textContent)
          },
          images: Array.from(document.querySelectorAll('img')).map(img => ({
            src: img.src,
            alt: img.alt,
            hasAlt: !!img.alt
          })),
          links: Array.from(document.querySelectorAll('a[href]')).length
        }));

        // Accessibility checks
        const a11yIssues = await page.evaluate(() => {
          const issues = [];

          // Check for missing alt text
          const imagesWithoutAlt = document.querySelectorAll('img:not([alt])');
          if (imagesWithoutAlt.length > 0) {
            issues.push(`${imagesWithoutAlt.length} images missing alt text`);
          }

          // Check for heading structure
          const headings = document.querySelectorAll('h1, h2, h3, h4, h5, h6');
          if (headings.length === 0) {
            issues.push('No headings found');
          }

          return issues;
        });

        // Take screenshot
        const screenshot = await page.screenshot({ fullPage: true });

        reports.push({
          url,
          metrics,
          seo: seoData,
          accessibility: a11yIssues,
          screenshot: screenshot.toString('base64'),
          timestamp: new Date().toISOString()
        });

      } catch (error) {
        reports.push({
          url,
          error: error.message,
          timestamp: new Date().toISOString()
        });
      } finally {
        await page.close();
      }
    }

    await browser.close();
    return reports;
  }
}

// Usage Examples
async function runExamples() {
  const automation = new PlaywrightBrowserless();

  try {
    // E-commerce automation
    console.log('🛒 Running e-commerce automation...');
    const ecommerceResults = await automation.automateEcommerce('https://example-shop.com');
    console.log(`Found ${ecommerceResults.products.length} products`);

    // Google search
    console.log('🔍 Performing Google search...');
    const searchResults = await automation.automateGoogleSearch('playwright automation');
    console.log(`Found ${searchResults.count} search results`);

    // Price monitoring
    console.log('💰 Monitoring prices...');
    const products = [
      { name: 'iPhone', url: 'https://example.com/iphone', lastKnownPrice: '$999' },
      { name: 'MacBook', url: 'https://example.com/macbook', lastKnownPrice: '$1299' }
    ];
    const priceResults = await automation.monitorPrices(products);
    console.log(`Monitored ${priceResults.length} products`);

    // Generate reports
    console.log('📊 Generating reports...');
    const reportUrls = ['https://example.com', 'https://github.com'];
    const reports = await automation.generateReports(reportUrls);
    console.log(`Generated ${reports.length} reports`);

    // Save all results
    const allResults = {
      ecommerce: ecommerceResults,
      search: searchResults,
      prices: priceResults,
      reports: reports,
      timestamp: new Date().toISOString()
    };

    require('fs').writeFileSync('automation-results.json', JSON.stringify(allResults, null, 2));
    console.log('✅ All results saved to automation-results.json');

  } catch (error) {
    console.error('❌ Automation failed:', error);
  }
}

// Run the examples
if (require.main === module) {
  runExamples();
}

